?x0 rdfs:subClassOf [ rdf:type owl:Restriction ; 
      owl:onProperty OntoDT:OntoDT_0000405;    
      owl:someValuesFrom $?PPx1$
 ] . 
?x0 rdfs:subClassOf* OntoDT:OntoDT_0000203 . 
$PPx1$ rdfs:subClassOf OntoDT2:OntoDT_691902.
}

